import '../../Stylesheets/LandingPage/Rodape.css'

export default function Rodape() {
  const footer = ['Sobre Nós','Política de Privacidade','Termos ']
  return (
    <div className="bg-branco w-full">
            <ul className='items-center inline-flex h-24'>
                <li className='text-base text-preto ml-[3vw] pr-[3vw]'>Sobre Nós</li>
                <li className='text-base text-preto ml-[3vw] pr-[3vw]'>Política de Privacidade</li>
                <li className='text-base text-preto ml-[3vw] pr-[3vw]'>Termos e Condições</li>
            </ul>
        </div>
  )
}
